Before making any changes, read apps/api/src/appointments/schemas/appointment.schema.ts if it exists and check what is already implemented. Do not duplicate any existing field, enum, or export. Follow all conventions defined in medicano_crew/docs/CONVENTIONS.md. Check medicano_crew/docs/specs/feature-registry.md to understand what already exists.

Create apps/api/src/appointments/schemas/appointment.schema.ts if it does not already exist:

export enum AppointmentStatus {
  SCHEDULED = 'scheduled',
  CONFIRMED = 'confirmed',
  CANCELLED = 'cancelled',
  COMPLETED = 'completed',
}

export const VALID_STATUS_TRANSITIONS: Record<AppointmentStatus, AppointmentStatus[]> = {
  [AppointmentStatus.SCHEDULED]: [AppointmentStatus.CONFIRMED, AppointmentStatus.CANCELLED],
  [AppointmentStatus.CONFIRMED]: [AppointmentStatus.COMPLETED, AppointmentStatus.CANCELLED],
  [AppointmentStatus.CANCELLED]: [],
  [AppointmentStatus.COMPLETED]: [],
};

@Schema({ timestamps: true }) class Appointment:
- clinicId: Types.ObjectId — @Prop({ type: Types.ObjectId, ref: 'Clinic', required: true })
- professionalId: Types.ObjectId — @Prop({ type: Types.ObjectId, ref: 'Professional', required: true })
- patientId: Types.ObjectId — @Prop({ type: Types.ObjectId, ref: 'User', required: true })
- startAt: Date — @Prop({ type: Date, required: true })
- endAt: Date — @Prop({ type: Date, required: true }) — computed by service from startAt + durationMinutes, stored for efficient conflict queries
- durationMinutes: number — @Prop({ type: Number, required: true, min: 15, max: 480 })
- status: AppointmentStatus — @Prop({ type: String, enum: AppointmentStatus, default: AppointmentStatus.SCHEDULED })
- notes?: string — @Prop({ type: String })

export type AppointmentDocument = Appointment & Document;
export const AppointmentSchema = SchemaFactory.createForClass(Appointment);

After schema creation add compound index for conflict detection:
AppointmentSchema.index({ professionalId: 1, startAt: 1, endAt: 1 });

Import Prop, Schema, SchemaFactory from '@nestjs/mongoose'. Import Document, Types from 'mongoose'.
